var UserConnection = Get<UserConnection>("UserConnection");
string request = Get<string>("Request");

try {
	var callback = new ActivationCallbackService(UserConnection);
	var response = callback.Process<CRMResponse.UpdateOrderStatusResponse>(request);

	var xmlString = HTTPRequest.XmlToString<CRMResponse.UpdateOrderStatusResponse>(response);
	Set("Response", xmlString);
} catch(Exception e) {
	Set("Message", e.Message);
}

return true;
